     1→import {
     2→  observe,
     3→  updateActiveObservation,
     4→  updateActiveTrace,
     5→} from "@langfuse/tracing";
     6→import { trace } from "@opentelemetry/api";
     7→import {
     8→  createAgentUIStreamResponse,
     9→  createUIMessageStream,
    10→  createUIMessageStreamResponse,
    11→  TypeValidationError,
    12→  type UIMessage,
    13→  validateUIMessages,
    14→} from "ai";
    15→import type { NextRequest } from "next/server";
    16→import { after } from "next/server";
    17→import { authenticateUser } from "@/lib/auth/utils";
    18→import {
    19→  type MediaAgentCallOptions,
    20→  mediaAgent,
    21→  mediaAgentTools,
    22→} from "@/lib/agents/media-agent";
    23→import {
    24→  createChat,
    25→  getChatById,
    26→} from "@/server/database/repo/postgress-repo-functions/chat.repo";
    27→import {
    28→  loadChatMessages,
    29→  saveChatMessage,
    30→} from "@/server/database/repo/postgress-repo-functions/chatMessage.repo";
    31→import { findProjectByIdForUser } from "@/server/database/repo/postgress-repo-functions/imageEditorProjects.repo";
    32→import logger from "@/utils/logger";
    33→import { langfuseSpanProcessor } from "../../../../../instrumentation";
    34→
    35→// Allow streaming up to 180s
    36→export const maxDuration = 180;
    37→
    38→const handler = async (req: NextRequest) => {
    39→  const requestId = crypto.randomUUID();
    40→  const { id: userId } = await authenticateUser(requestId);
    41→
    42→  // Get the last message, projectId, and optionally chatId from client
    43→  const {
    44→    message,
    45→    id: projectId,
    46→    chatId: clientChatId,
    47→    globalSystemInstructions,
    48→    modelSelection,
    49→  }: {
    50→    message: UIMessage;
    51→    id: string;
    52→    chatId?: string;
    53→    globalSystemInstructions?: string;
    54→    modelSelection?: {
    55→      isAutoMode: boolean;
    56→      imageModel: string | null;
    57→      videoModel: string | null;
    58→    };
    59→  } = await req.json();
    60→
    61→  // Log model selection for debugging
    62→  logger.info(`Model selection received: ${JSON.stringify(modelSelection)}`);
    63→
    64→  const initialTraceInput =
    65→    extractTextFromUiMessage(message) ??
    66→    `[${message.role}] ${summarizeParts(message.parts)}`;
    67→
    68→  try {
    69→    // Verify project exists and user owns it
    70→    const project = await findProjectByIdForUser({ projectId, userId });
    71→    if (!project) {
    72→      logger.error("Project not found or access denied");
    73→      return new Response(
    74→        JSON.stringify({ error: "Project not found or access denied" }),
    75→        { status: 403, headers: { "Content-Type": "application/json" } },
    76→      );
    77→    }
    78→
    79→    // Resolve or create chat
    80→    // Client always sends a chatId (either existing or pre-generated UUID)
    81→    let chat: Awaited<ReturnType<typeof getChatById>> | null = null;
    82→    let previousMessages: UIMessage[] = [];
    83→
    84→    if (!clientChatId) {
    85→      // Chat not found with provided chatId - create a new chat
    86→      logger.error("No chatId provided by client", {
    87→        requestId,
    88→        userId,
    89→        projectId,
    90→      });
    91→      return new Response(
    92→        JSON.stringify({
    93→          error:
    94→            "chatId is required but was not provided. This usually indicates an outdated or misconfigured client. Please refresh the page or update the client and try again.",
    95→        }),
    96→        {
    97→          status: 400,
    98→          headers: { "Content-Type": "application/json" },
    99→        },
   100→      );
   101→    }
   102→
   103→    // Update Langfuse trace with context (now that we have a chat/session id)
   104→    updateActiveTrace({
   105→      name: "agent-chat-message",
   106→      sessionId: clientChatId,
   107→      userId,
   108→      input: initialTraceInput,
   109→      metadata: {
   110→        projectId,
   111→        requestId,
   112→        isManualMode: modelSelection ? !modelSelection.isAutoMode : false,
   113→      },
   114→    });
   115→
   116→    updateActiveObservation({
   117→      input: initialTraceInput,
   118→    });
   119→
   120→    // Try to get existing chat
   121→    chat = await getChatById({ chatId: clientChatId, userId });
   122→
   123→    if (chat) {
   124→      // Existing chat - load messages
   125→      previousMessages = await loadChatMessages(chat.id, userId);
   126→    } else {
   127→      // No chatId provided - create a new chat
   128→
   129→      chat = await createChat({
   130→        id: clientChatId, // Use client's pre-generated ID
   131→        projectId,
   132→        userId,
   133→        title: "New Chat",
   134→      });
   135→
   136→      if (!chat) {
   137→        logger.error("Failed to create chat");
   138→        return new Response(
   139→          JSON.stringify({ error: "Failed to create chat" }),
   140→          { status: 500, headers: { "Content-Type": "application/json" } },
   141→        );
   142→      }
   143→      // No previous messages for new chat
   144→      previousMessages = [];
   145→    }
   146→
   147→    // Track continuation message ID to maintain consistent IDs across multi-step tool execution
   148→    // When client sends an assistant message (via sendAutomaticallyWhen), we reuse its ID
   149→    // so all steps share the same message ID (like DB upsert pattern)
   150→    let continuationMessageId: string | undefined;
   151→
   152→    // Build messages array for LLM based on incoming message role
   153→    let messages: UIMessage[];
   154→
   155→    if (message.role === "user") {
   156→      // User message: append to conversation history
   157→      messages = [...previousMessages, message];
   158→      logger.info(`User message received, total messages: ${messages.length}`);
   159→    } else if (message.role === "assistant") {
   160→      // Assistant message sent by client's sendAutomaticallyWhen
   161→      // Preserve the client's message ID for consistency
   162→      continuationMessageId = message.id;
   163→      // Use only previous messages (new assistant message will be generated)
   164→      messages = previousMessages;
   165→      logger.info(
   166→        `Assistant message received (auto-continuation), using ${messages.length} previous messages, continuationId: ${continuationMessageId}`,
   167→      );
   168→    } else {
   169→      // Unexpected role (system, etc.)
   170→      logger.warn(`Unexpected message role: ${message.role}`);
   171→      messages = [...previousMessages, message];
   172→    }
   173→
   174→    const bestTraceInput =
   175→      extractLatestUserTextFromUiMessages(messages) ?? initialTraceInput;
   176→
   177→    updateActiveObservation({ input: bestTraceInput });
   178→    updateActiveTrace({ input: bestTraceInput });
   179→
   180→    // Validate messages against tool schemas to ensure compatibility
   181→    let validatedMessages: UIMessage[];
   182→    try {
   183→      validatedMessages = await validateUIMessages({
   184→        messages,
   185→        // biome-ignore lint/suspicious/noExplicitAny: Because we have specific tightly typed tools types
   186→        tools: mediaAgentTools as any,
   187→      });
   188→    } catch (error) {
   189→      if (error instanceof TypeValidationError) {
   190→        // Log validation error for monitoring
   191→        logger.warn(
   192→          `Message validation failed, starting with only new message: ${error.message}`,
   193→        );
   194→        // If validation fails (e.g., old tool schemas), start fresh with just the new message
   195→        validatedMessages = [message];
   196→      } else {
   197→        throw error;
   198→      }
   199→    }
   200→
   201→    // Save user message to database immediately (before streaming)
   202→    // Assistant messages are saved in onFinish callback after streaming completes
   203→    if (message.role === "user") {
   204→      await saveChatMessage({ message, chatId: chat.id, userId });
   205→      logger.info(`User message saved: ${message.id}`);
   206→    }
   207→    // Build agent call options from request
   208→    const agentOptions: MediaAgentCallOptions = {
   209→      isAutoMode: modelSelection?.isAutoMode ?? true,
   210→      imageModel: modelSelection?.imageModel ?? null,
   211→      videoModel: modelSelection?.videoModel ?? null,
   212→      globalSystemInstructions: globalSystemInstructions?.trim(),
   213→    };
   214→
   215→    // Flush Langfuse traces after the response is sent (serverless-friendly)
   216→    after(async () => {
   217→      await langfuseSpanProcessor.forceFlush();
   218→    });
   219→
   220→    // Return agent UI stream response with createAgentUIStreamResponse
   221→    return await createAgentUIStreamResponse({
   222→      agent: mediaAgent,
   223→      uiMessages: validatedMessages,
   224→      options: agentOptions,
   225→      // Use continuation message ID for multi-step tool execution (upsert pattern)
   226→      // This ensures client receives consistent IDs across all steps
   227→      generateMessageId: () => continuationMessageId || crypto.randomUUID(),
   228→      onError: (error) => {
   229→        // Enhanced error logging with type checking
   230→        if (error instanceof Error) {
   231→          logger.error(
   232→            `Stream error occurred: name=${error.name}, message=${error.message}, requestId=${requestId}, stack=${error.stack}`,
   233→          );
   234→        } else {
   235→          logger.error(
   236→            `Unknown stream error: error=${JSON.stringify(error)}, requestId=${requestId}`,
   237→          );
   238→        }
   239→
   240→        // Return context-aware error messages
   241→        const errorMessage = error instanceof Error ? error.message : "";
   242→
   243→        if (errorMessage.includes("rate limit")) {
   244→          return "I'm experiencing high demand right now. Please try again in a moment.";
   245→        }
   246→
   247→        if (errorMessage.includes("timeout")) {
   248→          return "The request took too long. Please try a simpler question.";
   249→        }
   250→
   251→        if (errorMessage.includes("context length")) {
   252→          return "The conversation is too long. Please start a new chat.";
   253→        }
   254→
   255→        const messageToUser =
   256→          "Sorry, I am not able to respond right now. Please try again later.";
   257→
   258→        updateActiveObservation({
   259→          output: messageToUser,
   260→          level: "ERROR",
   261→        });
   262→        updateActiveTrace({
   263→          output: messageToUser,
   264→        });
   265→
   266→        trace.getActiveSpan()?.end();
   267→        return messageToUser;
   268→      },
   269→      onFinish: async ({ responseMessage }) => {
   270→        // Update Langfuse trace with output
   271→        const outputText = responseMessage
   272→          ? extractTextFromUiMessage(responseMessage)
   273→          : undefined;
   274→
   275→        const outputForTrace =
   276→          outputText ??
   277→          (responseMessage
   278→            ? `[assistant] ${summarizeParts(responseMessage.parts)}`
   279→            : undefined);
   280→
   281→        updateActiveObservation({
   282→          output: outputForTrace,
   283→        });
   284→
   285→        updateActiveTrace({
   286→          output: outputForTrace,
   287→        });
   288→
   289→        trace.getActiveSpan()?.end();
   290→
   291→        // Save assistant response message to database
   292→        // Upsert will update if already exists (from previous tool-only saves)
   293→        if (responseMessage && responseMessage.parts.length > 0) {
   294→          // ID priority: responseMessage.id > continuationMessageId > new UUID
   295→          // This ensures multi-step tool executions share the same message ID
   296→          const messageId =
   297→            responseMessage.id || continuationMessageId || crypto.randomUUID();
   298→
   299→          const messageToSave: UIMessage = {
   300→            ...responseMessage,
   301→            id: messageId,
   302→          };
   303→
   304→          try {
   305→            await saveChatMessage({
   306→              message: messageToSave,
   307→              chatId: chat.id,
   308→              userId,
   309→            });
   310→            logger.info(
   311→              `Assistant message saved: ${messageToSave.id} (${messageToSave.parts.length} parts)`,
   312→            );
   313→          } catch (saveError) {
   314→            logger.error(
   315→              `Failed to save assistant message: ${saveError instanceof Error ? saveError.message : String(saveError)}`,
   316→            );
   317→          }
   318→        } else if (responseMessage && responseMessage.parts.length === 0) {
   319→          logger.warn(
   320→            `Skipping save of assistant message ${responseMessage.id || "unknown"} - 0 parts (intermediate state)`,
   321→          );
   322→        }
   323→      },
   324→    });
   325→  } catch (error) {
   326→    // Enhanced pre-stream error logging
   327→    const errorMessage =
   328→      error instanceof Error ? error.message : "Unknown error";
   329→    const stack = error instanceof Error ? error.stack : "no stack";
   330→    logger.error(
   331→      `Error in POST request (before streaming): error=${errorMessage}, requestId=${requestId}, stack=${stack}`,
   332→    );
   333→
   334→    // Update Langfuse trace with error
   335→    updateActiveObservation({
   336→      output: errorMessage,
   337→      level: "ERROR",
   338→    });
   339→
   340→    updateActiveTrace({
   341→      output: errorMessage,
   342→    });
   343→
   344→    trace.getActiveSpan()?.end();
   345→
   346→    try {
   347→      const textId = crypto.randomUUID();
   348→
   349→      const stream = createUIMessageStream<UIMessage>({
   350→        originalMessages: [message],
   351→        execute: ({ writer }) => {
   352→          writer.write({ type: "text-start", id: textId });
   353→          writer.write({
   354→            type: "text-delta",
   355→            id: textId,
   356→            delta:
   357→              "Sorry, I am not able to respond right now. Please try again later.",
   358→          });
   359→          writer.write({ type: "text-end", id: textId });
   360→        },
   361→      });
   362→
   363→      return createUIMessageStreamResponse({ stream });
   364→    } catch (streamError) {
   365→      const streamErrorMsg =
   366→        streamError instanceof Error
   367→          ? streamError.message
   368→          : String(streamError);
   369→      logger.error(
   370→        `Failed to create error stream: error=${streamErrorMsg}, requestId=${requestId}`,
   371→      );
   372→
   373→      // Fallback to plain text response if stream creation fails
   374→      return new Response(
   375→        JSON.stringify({
   376→          error:
   377→            "An error occurred while processing your request. Please try again.",
   378→        }),
   379→        {
   380→          status: 500,
   381→          headers: { "Content-Type": "application/json" },
   382→        },
   383→      );
   384→    }
   385→  }
   386→};
   387→
   388→// Wrap handler with Langfuse observe for automatic tracing
   389→// endOnExit: false keeps the observation open during streaming
   390→export const POST = observe(handler, {
   391→  name: "handle-agent-chat",
   392→  endOnExit: false,
   393→});
   394→
   395→function extractTextFromUiMessage(message: UIMessage): string | undefined {
   396→  return extractTextFromParts(message.parts);
   397→}
   398→
   399→function extractTextFromParts(parts: UIMessage["parts"]): string | undefined {
   400→  const chunks: string[] = [];
   401→  for (const part of parts) {
   402→    if (part.type === "text") {
   403→      chunks.push(part.text);
   404→    }
   405→  }
   406→  const text = chunks.join("");
   407→  return text.trim().length ? text : undefined;
   408→}
   409→
   410→function extractLatestUserTextFromUiMessages(
   411→  messages: UIMessage[],
   412→): string | undefined {
   413→  for (let i = messages.length - 1; i >= 0; i -= 1) {
   414→    const msg = messages[i];
   415→    if (msg.role !== "user") continue;
   416→    const text = extractTextFromUiMessage(msg);
   417→    if (text) return text;
   418→  }
   419→  return;
   420→}
   421→
   422→function summarizeParts(parts: UIMessage["parts"]): string {
   423→  const counts = new Map<string, number>();
   424→  for (const part of parts) {
   425→    counts.set(part.type, (counts.get(part.type) ?? 0) + 1);
   426→  }
   427→  const summary = [...counts.entries()]
   428→    .map(([type, count]) => `${type}:${count}`)
   429→    .join(", ");
   430→
   431→  return summary.length ? `parts(${summary})` : "parts(empty)";
   432→}
